+             "The other operand must have the main opcode.");
+      std::swap(Op1, Op2);
+    }
+
     SmallVector<Value *> NewVL(VL.size());
     copy(Op1, NewVL.begin());
     copy(Op2, std::next(NewVL.begin(), Op1.size()));
